var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아윽……!?","JPN":"あうっ……！？","ENG":"Urgh!","TWN":"唔……！？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"물건 확보. 임무 완수. 전군 철수 준비.","JPN":"ターゲット確保。任務完遂。全軍、撤退準備。","ENG":"We got what we came for. Mission accomplished. Everyone, withdraw.","TWN":"東西到手。任務完成，全軍撤退。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"제이나 양!","JPN":"ジェイナ！","ENG":"Jaina!","TWN":"婕娜！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이런, 리액터를 빼앗겼나?!","JPN":"くそ、リアクターを奪われたのか！？","ENG":"They took the reactor?","TWN":"可惡！反應爐被搶走了嗎？！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"순순히 넘겨 줄 수는…… 없지!","JPN":"そんな簡単に渡すわけには……いかない！","ENG":"I can’t just let them get away with it!","TWN":"怎麼可以這麼簡單……就被他們搶走！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"크윽?!","JPN":"くうっ！？","ENG":"Huh?!","TWN":"唔？！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"대령의 공격을 가볍게 막아냈어?","JPN":"大佐の攻撃を軽く止めただと？","ENG":"She repelled the Colonel’s attack easily?","TWN":"竟然可以輕易擋下上校的攻擊？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"대체 저런 괴물들이 어디서 자꾸 나타나는 거야?!","JPN":"いったいどこからあんな化け物が次々と現れるんだ！？","ENG":"Where the hell do these monsters keep appearing?!","TWN":"這些怪物到底都是從哪裡冒出來的啦！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"나의 임무는 여기까지. 그대들과 더 이상 싸울 이유는 없다, 이방인.","JPN":"私の任務はここまでだ。お前たちとこれ以上戦う理由はない、異邦人よ。","ENG":"My duty here is done. I have no reason to fight you, outsiders.","TWN":"外邦人，我的任務已經完成，沒有理由再繼續和你們打下去。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"미안하지만 이 쪽은 아직 볼 일이 안 끝났어!","JPN":"悪いが、こっちはまだ用事が済んでないんでね！","ENG":"Well, sorry. I’m not done with you!","TWN":"不好意思喔，但我們的任務還沒完成！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"자기 일만 끝내고 멋대로 도망치는 건 나쁜 일이라고, 아가씨!","JPN":"自分の用事だけ済ませて勝手に逃げるのは悪いことだよ、お嬢ちゃん！","ENG":"You can’t just run because you’re done here! That's bad!","TWN":"小丫頭，自己的事情完成就逃走是不好的行為喔！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"그런가. 새로운 가르침에 감사한다.","JPN":"そうなのか。新しい教えに感謝する。","ENG":"I see. Thank you for another lesson.","TWN":"是嗎？再次謝謝你的教導。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"하지만 나에겐 다음 임무가 있어 지체할 수 없다.","JPN":"だが、私には次の任務があり、遅れることはできない。","ENG":"But I have a job to do. I can’t stay here any longer.","TWN":"不過我接下來還有其他任務，請恕我無法奉陪。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"사과는 그 이후에 하겠다.","JPN":"謝罪はその後にさせてもらう。","ENG":"I will apologize later.","TWN":"之後再向你們致歉。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"천장이 무너진다! 이대로는 생매장 되어버릴 거야!","JPN":"天井が崩れる！　このままじゃ生き埋めだ！","ENG":"The ceiling is collapsing! We’ll be buried alive!","TWN":"天花板要塌了！!我們要被活埋了啦！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이런, 젠장……!","JPN":"……クソ！","ENG":"Oh, drat!","TWN":"該死……！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"쿨럭……! 쿨럭!!","JPN":"ケホッ！　ケホッ！！","ENG":"*Cough* *Cough*","TWN":"咳咳……！咳咳咳！！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"방금 그 기사들은…… 전부 사라진 건가?","JPN":"さっきの騎士たちは……全員消えたのか？","ENG":"The knights... They are all gone?","TWN":"剛剛那些騎士……全都消失了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그보다 내가 어떻게 살아있는 거지? 꼼짝 없이 죽는 줄 알았는데……?","JPN":"それより、なんで俺は生きてるんだ？　間違いなくあの世行きだと思ったのに……？","ENG":"How am I still alive? I thought I was going to die for sure.","TWN":"不過我怎麼還活著？我還以為我死定咧……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……멀쩡해 보이는군. 어디 한 군데 부러졌으면 좋았을 텐데.","JPN":"……無事だったみたいだな。どこか一か所くらい折れちまったらよかったのに。","ENG":"... You seem fine. It would be better you broke your arm or something.","TWN":"……你看起來很好啊！怎麼沒有缺隻手還缺條腿的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"설마 대령…… 그쪽이 떨어지던 잔해들을 모두 파괴한 건가?","JPN":"まさか、大佐……あんたが崩れ落ちる残骸をすべて壊したのか？","ENG":"Colonel... You destroyed all the falling debris?","TWN":"難道……是你把那些掉落的碎石全都弄掉的嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"어째서? 용병을 싫어하는 줄 알았는데?","JPN":"どうしてだ？　傭兵嫌いだと思っていたが。","ENG":"But why? I thought you hated mercenaries.","TWN":"怎麼會？你不是很討厭傭兵嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"유감스럽게도 지금은 그 용병이 동료라서 말이야.","JPN":"残念ながら、今はその傭兵が仲間なんでね。","ENG":"Well, that mercenary happens to be my partner now.","TWN":"誰叫那個傭兵現在是一起行動的夥伴。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"상황이 좋지 않아도 동료를 버리지는 않아.","JPN":"状況が悪くなったからって、仲間を見捨てるなんてことはしない。","ENG":"And I would never abandon my partner.","TWN":"無論在什麼情況下，我都不會扔下夥伴不管的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……그거 고마운 소리군.","JPN":"……それはありがたいことだな。","ENG":"... Well, I appreciate that.","TWN":"……還真是謝謝喔。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그나저나 이대로라면 의뢰는 실패인걸. 곤란한데…….","JPN":"ところで、このままだと依頼は失敗か。まいったな……","ENG":"But it seems our mission is a failure. What do we do?","TWN":"不過，這樣算是沒有完成委託吧？這下該怎麼辦才好……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저, 제게 방법이 있는 것 같아요.","JPN":"あの……私に案があります。","ENG":"Erm, I know what to do.","TWN":"我…我好像有辦法。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아마도……","JPN":"たぶん……","ENG":"I think...","TWN":"應該吧……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"뭐? 그게 무슨 소리지?","JPN":"うん？　どういうことだ？","ENG":"Huh? What do you mean?","TWN":"嗯？什麼意思？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그게…… 지금처럼 노바급 리액터를 분실할 때를 대비해서 내부에 소형 발신기가 장착되어 있었던 기억이 나요.","JPN":"それが……今回のようなノヴァ級リアクターを失った時に備えて、\\n小型発信機が付けられていた記憶があります。","ENG":"Well... I remember a small transmitter was installed in the reactor, just in case it was stolen.","TWN":"那個……我記得，為了因應這種情況，諾瓦反應爐裡面裝有小型發射器。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"정말인가?!","JPN":"本当か！？","ENG":"Really?!","TWN":"真的嗎？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 아마도요……?","JPN":"た、たぶん……？","ENG":"I-I think so?","TWN":"應…應該吧……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 어떻게 추적해야 하는지 구체적인 방법은 잘 모르겠어요.","JPN":"でも、どうやって追跡すればいいのか、\\n具体的な方法はわかりません。","ENG":"But I don’t know how to track it.","TWN":"但我不確定要如何追蹤。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이런, 그러면 의미가 없잖아.","JPN":"まじか、それじゃあ意味ないだろ？","ENG":"Oh, then what’s the point?","TWN":"真是的，那這樣有說跟沒說一樣嘛！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"걱정하지 말라고. 그런 일은 내 전문이니까.","JPN":"心配するな。それは俺の専門分野だ。","ENG":"Don’t worry, I know what to do.","TWN":"放心吧！這種事我是專門的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"여길 벗어나는 대로 신호 주파수만 알려 달라고.","JPN":"ここから出次第、シグナルの周波数だけ教えてくれ。","ENG":"Give me the frequency when we get out of here.","TWN":"只要離開這裡後告訴我信號頻率就好。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};